module LDO (
    input wire [7:0] LDORedux_Vref,
    input wire [7:0] Vin,
    input wire EN,
    output reg [7:0] Vout
);
    always @(*) begin
        if (EN) begin
            if (Vin > LDORedux_Vref)
                Vout = LDORedux_Vref;
            else
                Vout = 8'b0;
        end else begin
            Vout = 8'b0;
        end
    end
endmodule
